solution_code:
#include <iostream>

class Rect {
    int m_width;
    int m_height;
public:
    Rect(int w, int h) : m_width{ w }, m_height{ h } {}
    friend int perimeter(const Rect& r);
};

int perimeter(const Rect& r) {
    return 2 * (r.m_width + r.m_height);
}

int main() {
    int w, h;
    std::cin >> w >> h;
    Rect r{ w, h };
    std::cout << "Perimeter: " << perimeter(r) << "\n";
    return 0;
}

