solution_code:
#include <iostream>
#include <cstdlib>

class Point {
    int m_x;
    int m_y;
public:
    Point(int x, int y) : m_x{ x }, m_y{ y } {}
    friend int distanceBetween(const Point& a, const Point& b);
};

int distanceBetween(const Point& a, const Point& b) {
    return std::abs(a.m_x - b.m_x) + std::abs(a.m_y - b.m_y);
}

int main() {
    int x1, y1, x2, y2;
    std::cin >> x1 >> y1 >> x2 >> y2;
    Point p1{ x1, y1 };
    Point p2{ x2, y2 };
    std::cout << "Distance: " << distanceBetween(p1, p2) << "\n";
    return 0;
}
